import redis
import json
import sys
from typing import Any, Optional


class RedisLuaClient:
    """Redis client that executes Lua scripts for complex cache operations."""

    def __init__(self, host: str = "localhost", port: int = 6379, db: int = 0,
                 password: Optional[str] = None, decode_responses: bool = True):
        """Initialize Redis connection."""
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=decode_responses
        )
        self._script_cache = {}
        self._verify_connection()

    def _verify_connection(self):
        """Verify Redis connection is alive."""
        try:
            self.client.ping()
            print("[OK] Connected to Redis successfully.")
        except redis.ConnectionError as e:
            print(f"[ERROR] Failed to connect to Redis: {e}")
            raise

    def execute_lua_script(self, script: str, keys: list = None, args: list = None) -> Any:
        """
        Execute a Lua script against Redis.

        Args:
            script: Lua script code to execute
            keys: List of Redis keys referenced in the script (KEYS[1], KEYS[2], ...)
            args: List of arguments passed to the script (ARGV[1], ARGV[2], ...)

        Returns:
            Result of the Lua script execution
        """
        keys = keys or []
        args = args or []

        # Sanitize inputs - convert all to strings for Redis
        sanitized_keys = [str(k) for k in keys]
        sanitized_args = [str(a) for a in args]

        try:
            result = self.client.eval(script, len(sanitized_keys), *sanitized_keys, *sanitized_args)
            return result
        except redis.exceptions.ResponseError as e:
            print(f"[ERROR] Lua script execution failed: {e}")
            raise
        except Exception as e:
            print(f"[ERROR] Unexpected error: {e}")
            raise

    def register_script(self, name: str, script: str):
        """
        Register and cache a Lua script for repeated execution.
        Uses SCRIPT LOAD for efficiency.

        Args:
            name: Name to identify the script
            script: Lua script code
        """
        try:
            registered = self.client.register_script(script)
            self._script_cache[name] = registered
            print(f"[OK] Script '{name}' registered successfully.")
        except Exception as e:
            print(f"[ERROR] Failed to register script '{name}': {e}")
            raise

    def execute_registered_script(self, name: str, keys: list = None, args: list = None) -> Any:
        """
        Execute a previously registered Lua script.

        Args:
            name: Name of the registered script
            keys: List of Redis keys
            args: List of arguments

        Returns:
            Result of the script execution
        """
        if name not in self._script_cache:
            raise ValueError(f"Script '{name}' not found. Register it first.")

        keys = keys or []
        args = args or []

        try:
            result = self._script_cache[name](keys=[str(k) for k in keys],
                                               args=[str(a) for a in args])
            return result
        except redis.exceptions.ResponseError as e:
            print(f"[ERROR] Registered script '{name}' execution failed: {e}")
            raise

    def list_registered_scripts(self) -> list:
        """List all registered script names."""
        return list(self._script_cache.keys())

    def flush_script_cache(self):
        """Flush all cached scripts from Redis and local cache."""
        self.client.script_flush()
        self._script_cache.clear()
        print("[OK] Script cache flushed.")


